glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float time;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453); }
float noise(vec2 p){ vec2 i=floor(p); vec2 f=fract(p); f=f*f*(3.0-2.0*f); float a=hash(i); float b=hash(i+vec2(1.0,0.0)); float c=hash(i+vec2(0.0,1.0)); float d=hash(i+vec2(1.0,1.0)); return mix(mix(a,b,f.x),mix(c,d,f.x),f.y); }
void main(){
 vec2 uv = vUv;
 float grain = noise(uv * 135.0) * 0.055 + noise(uv * 38.0) * 0.075;
 float bands = sin((uv.y * 10.5) + noise(vec2(uv.x * 2.0, uv.y * 7.0)) * 1.8) * 0.035;
 float wash = noise(uv * vec2(4.2, 2.8)) * 0.10;
 vec3 ochre = vec3(0.78, 0.64, 0.38);
 vec3 paper = vec3(0.88, 0.77, 0.55);
 vec3 color = mix(paper, ochre, 0.42 + wash + bands) + grain;
 float edge = smoothstep(0.0, 0.16, uv.x) * smoothstep(0.0, 0.16, 1.0 - uv.x) * smoothstep(0.0, 0.12, uv.y) * smoothstep(0.0, 0.12, 1.0 - uv.y);
 color *= mix(0.94, 1.02, edge);
 gl_FragColor = vec4(color, 1.0);
}

glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float time;
float oval(vec2 p, vec2 c, vec2 r){ vec2 q=(p-c)/r; return 1.0-smoothstep(0.72,1.08,dot(q,q)); }
float softEdge(vec2 p, vec2 c, vec2 r){ vec2 q=(p-c)/r; float d=dot(q,q); return smoothstep(1.28,0.55,d); }
void main(){
 vec2 uv = vUv;
 float bloomPulse = sin(time * 0.35) * 0.025;
 float g1 = softEdge(uv, vec2(0.30,0.54 + bloomPulse), vec2(0.42,0.22));
 float g2 = softEdge(uv, vec2(0.63,0.44 - bloomPulse), vec2(0.38,0.18));
 float p1 = softEdge(uv, vec2(0.44,0.40), vec2(0.46,0.20));
 float p2 = softEdge(uv, vec2(0.71,0.62), vec2(0.30,0.15));
 float green = clamp(g1 + g2 * 0.75, 0.0, 1.0);
 float pink = clamp(p1 * 0.82 + p2 * 0.70, 0.0, 1.0);
 float alpha = clamp((green + pink) * 0.42, 0.0, 0.58);
 vec3 greenCol = vec3(0.47,0.60,0.34);
 vec3 pinkCol = vec3(0.86,0.57,0.60);
 vec3 mixed = (greenCol * green + pinkCol * pink) / max(green + pink, 0.001);
 float boundaryReserve = 1.0 - oval(uv, vec2(0.5,0.5), vec2(0.050,0.84)) * 0.20;
 gl_FragColor = vec4(mixed, alpha * boundaryReserve);
}
